import Stripe

class ViewController: UIViewController {
    @IBOutlet weak var mapView: GMSMapView!
    @IBOutlet weak var payButton: UIButton!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupGoogleMaps()
        setupStripe()
        setupUI()
    }
    
    func setupGoogleMaps() {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12.0)
        mapView.camera = camera
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.settings.compassButton = true
        mapView.settings.zoomGestures = true
    }
    
    func setupStripe() {
        STPAPIClient.shared.publishableKey = "pk_test_Stripe51234567890"
    }
    
    func setupUI() {
        payButton.backgroundColor = .systemBlue
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 8
        payButton.setTitle("Pay with Stripe", for: .normal)
        payButton.addTarget(self, action: #selector(payButtonTapped), for: .touchUpInside)
    }
    
    @objc func payButtonTapped() {
        let paymentIntentParams = STPPaymentIntentParams(clientSecret: "pi_test_secret")
        paymentIntentParams.paymentMethodParams = STPPaymentMethodParams(card: STPPaymentMethodCardParams(number: "4242424242424242", expMonth: 12, expYear: 2025, cvc: "123"))
        
        STPPaymentHandler.shared.confirmPayment(paymentIntentParams, with: self) { (status, paymentIntent, error) in
            switch status {
            case .succeeded:
                DispatchQueue.main.async {
                    self.showAlert(title: "Success", message: "Payment completed successfully!")
                }
            case .failed:
                DispatchQueue.main.async {
                    self.showAlert(title: "Failed", message: error?.localizedDescription ?? "Payment failed")
                }
            case .canceled:
                break
            @unknown default:
                break
